import { index, jsonb, pgTable, text, timestamp, uuid } from "drizzle-orm/pg-core";

export const auditLogEvents = pgTable(
  "audit_log_events",
  {
    id: uuid("id").primaryKey().defaultRandom(),
    actorId: text("actor_id"),
    actorType: text("actor_type").notNull().default("user"),
    action: text("action").notNull(),
    resourceType: text("resource_type").notNull(),
    resourceId: text("resource_id"),
    organizationId: text("organization_id"),
    metadata: jsonb("metadata").$type<Record<string, unknown>>().notNull().default({}),
    createdAt: timestamp("created_at", { withTimezone: true }).defaultNow().notNull(),
  },
  (table) => [
    index("audit_log_events_org_idx").on(table.organizationId),
    index("audit_log_events_resource_idx").on(table.resourceType, table.resourceId),
  ]
);

import "server-only";

export type AuditLogEventInput = {
  actorId?: string | null;
  actorType?: "user" | "system" | "service";
  action: string;
  resourceType: string;
  resourceId?: string | null;
  organizationId?: string | null;
  metadata?: Record<string, unknown>;
};

export function buildAuditLogEvent(input: AuditLogEventInput) {
  return {
    actorId: input.actorId ?? null,
    actorType: input.actorType ?? "user",
    action: input.action,
    resourceType: input.resourceType,
    resourceId: input.resourceId ?? null,
    organizationId: input.organizationId ?? null,
    metadata: input.metadata ?? {},
  };
}

export function assertAuditAction(action: string) {
  if (!/^[a-z]+(?:\.[a-z]+)+$/.test(action)) {
    throw new Error("Audit actions should use a namespaced form like billing.subscription_updated");
  }
}

const exampleEvents = [
  { action: "billing.subscription_updated", actor: "system", resource: "subscription" },
  { action: "api_key.created", actor: "user_123", resource: "api_key" },
  { action: "workspace.member_invited", actor: "user_456", resource: "invite" },
];

export default function AuditLogPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Audit Log</h1>
        <p className="text-muted-foreground">Review sensitive account, workspace, and system events.</p>
      </div>
      <div className="grid gap-3">
        {exampleEvents.map((event) => (
          <div key={event.action} className="rounded-lg border p-4">
            <p className="font-medium">{event.action}</p>
            <p className="text-sm text-muted-foreground">{event.actor} changed {event.resource}</p>
          </div>
        ))}
      </div>
    </main>
  );
}
